// Mode-aware filter.
// application: build exactly the jobs whose job_id is in the run's payload list (job_ids).
//   Selection is per-run and explicit, passed in from the orchestrator's webhook body.
//   processed_status is NOT used for selection (it's display-only now), so overlapping
//   or repeat runs can't collide â€” each run builds only the ids it was handed.
// discovery: existing job URLs + existing (company,title,date) role keys for dedup.
//
// "Always Output Data" is ON for this node so an empty jobs sheet (Load Jobs returns
// nothing) still produces the discovery summary item with empty arrays, rather than
// n8n marking the node "didn't execute" and breaking downstream $('Filter Jobs') refs.

const mode = String($('Trigger').first().json.mode || 'application').toLowerCase().trim();
const allJobs = $input.all();

// company || title || YYYY-MM-DD (date only; undated -> trailing empty slot).
// MUST stay byte-identical to the same helper in Job Post Processing > Dedup.
const roleKey = (company, title, postedAt) => {
  const norm = (s) => String(s || '').toLowerCase().replace(/\s+/g, ' ').trim();
  const c = norm(company);
  const t = norm(title);
  if (!c || !t) return '';
  let d = '';
  const s = String(postedAt || '').trim();
  if (s) {
    const m = s.match(/^(\d{4}-\d{2}-\d{2})/);
    if (m) d = m[1];
    else { const dt = new Date(s); d = isNaN(dt.getTime()) ? '' : dt.toISOString().slice(0, 10); }
  }
  return `${c}||${t}||${d}`;
};

if (mode === 'discovery') {
  // Tolerate empty Load Jobs (new database, no rows yet). Empty arrays are the
  // correct semantic answer: no prior URLs/roles to dedup against.
  const urls = allJobs
    .map(item => (item && item.json) ? item.json.url : null)
    .filter(url => !!url);
  const roles = [...new Set(
    allJobs
      .map(item => (item && item.json) ? roleKey(item.json.company, item.json.title, item.json.posted_at) : '')
      .filter(Boolean)
  )];
  console.log(`[Filter Jobs] mode=discovery, input rows=${allJobs.length}, returning ${urls.length} existing URLs, ${roles.length} existing role keys`);
  return [{ json: { existing_job_urls: urls, existing_job_roles: roles } }];
}

// mode=application: select by explicit job_ids from the payload.
let requested = $('Trigger').first().json.job_ids;

// Normalize: accept array, JSON string, or comma-separated string.
if (typeof requested === 'string') {
  const raw = requested.trim();
  if (raw.startsWith('[')) {
    try { requested = JSON.parse(raw); } catch (e) { requested = raw.split(','); }
  } else {
    requested = raw ? raw.split(',') : [];
  }
}
if (!Array.isArray(requested)) requested = [];
const wanted = new Set(requested.map(id => String(id).trim()).filter(Boolean));

if (wanted.size === 0) {
  console.log('[Filter Jobs] mode=application, no job_ids in payload â€” selecting nothing.');
  return [];
}

const selected = allJobs.filter(item => {
  const j = item && item.json;
  return j && wanted.has(String(j.job_id ?? '').trim());
});

const foundIds = new Set(selected.map(item => String(item.json.job_id).trim()));
const missing = [...wanted].filter(id => !foundIds.has(id));
if (missing.length) {
  console.log(`[Filter Jobs] WARNING: ${missing.length} requested job_id(s) not found: ${missing.join(', ')}`);
}

console.log(`[Filter Jobs] mode=application, requested: ${wanted.size}, selected: ${selected.length}`);
selected.forEach((item, idx) => {
  const j = item.json;
  console.log(`  ${idx + 1}. [${j.job_id}] [${j.company}] ${j.title}`);
});

return selected;

// Validates the master career doc has substantive content.

const text = $input.first()?.json?.data || $input.first()?.json?.text || '';

if (!text || text.length < 500) {
  throw new Error(
    `[Verify Master Doc] Master career doc is empty or too short (${text.length} chars). ` +
    `Expected at least 500 chars of career history.`
  );
}

console.log(`[Verify Master Doc] OK â€” ${text.length} chars`);

return [{ json: { master_doc: text } }];

// Aggregates config sheet rows into a single Object keyed by Parameter name.

const stripEquals = (val) => {
  if (typeof val !== 'string') return val;
  return val.startsWith('=') ? val.substring(1) : val;
};

const rows = $input.all().map(i => i.json);
const config = {};

rows.forEach(row => {
  const param = (row.Parameter ?? row.parameter ?? '').toString().trim();
  let value = row.Value !== undefined ? row.Value : row.value;
  value = stripEquals(value);
  if (param) {
    config[param] = value;
  }
});

console.log(`[Parse Config] Loaded ${Object.keys(config).length} config values`);

return [{ json: { config } }];

// Data Loader â€” find Master Career Document and database in root folder by name.
// Matches by name only (names must be unique inside the root folder).

const items = $input.all().map(i => i.json);

const findOne = (name) => {
  const matches = items.filter(i => i.name === name);
  if (matches.length === 0) {
    const available = items.length
      ? items.map(i => `  - "${i.name}"`).join('\n')
      : '  (folder is empty or list call returned nothing)';
    throw new Error(
      `[Data Loader] Could not find "${name}" in root folder.\n` +
      `Available items:\n${available}`
    );
  }
  if (matches.length > 1) {
    throw new Error(
      `[Data Loader] Multiple items named "${name}" found. Names must be unique in root folder.`
    );
  }
  return matches[0].id;
};

const master_doc_id = findOne('Master Career Document');
const database_id = findOne('Database');

console.log(`[Data Loader] Resolved IDs:`);
console.log(`  master_doc_id: ${master_doc_id}`);
console.log(`  database_id: ${database_id}`);

return [{ json: { master_doc_id, database_id } }];

// Mode-aware output shape. master_doc + database_id are loaded in all modes.
// application:  { run_id, mode, ready_jobs, config, master_doc, database_id, root_folder_id, pricing }
// discovery:    { run_id, mode, config, master_doc, database_id, root_folder_id, existing_job_urls, existing_job_roles, watchlist, pricing }
// refinement:   { run_id, mode, config, master_doc, database_id, root_folder_id, pricing }  â€” single known job; no job scan/watchlist
// cover_letter: { run_id, mode, config, master_doc, database_id, root_folder_id, pricing }  â€” single known job; no job scan/watchlist
// run_id is derived from parent workflow's $execution.id (passed via Trigger input)
// and mode-based prefix. Used as cross-sheet join key.
// root_folder_id is echoed from the Trigger input so downstream consumers (recorders)
// source it here instead of from config.drive_root_folder_id.

const mode = String($('Trigger').first().json.mode || 'application').toLowerCase().trim();

const parentExecutionId = String($('Trigger').first().json.parent_execution_id || '').trim();
if (!parentExecutionId) {
  throw new Error('[Bundle Output] parent_execution_id missing from Trigger â€” caller must pass {{ $execution.id }}');
}
const prefix = mode === 'discovery' ? 'disc_' :
                  mode === 'refinement' ? 'refine_' :
                  mode === 'cover_letter' ? 'cl_' : 'app_';
const runId = prefix + parentExecutionId;

const config = $('Parse Config').first()?.json?.config;
if (!config || Object.keys(config).length === 0) {
  throw new Error('[Bundle Output] config missing or empty from Parse Config');
}
const databaseId = $('Resolve File IDs').first()?.json?.database_id;
if (!databaseId) {
  throw new Error('[Bundle Output] database_id missing from Resolve File IDs');
}
const rootFolderId = String($('Trigger').first().json.root_folder_id || '').trim();
if (!rootFolderId) {
  throw new Error('[Bundle Output] root_folder_id missing from Trigger â€” caller must pass it');
}
let masterDoc = '';
try {
  masterDoc = $('Verify Master Doc').first()?.json?.master_doc || '';
} catch (e) {
  throw new Error(`[Bundle Output] Verify Master Doc did not execute: ${e.message}`);
}
if (!masterDoc) {
  throw new Error('[Bundle Output] master_doc missing or empty from Verify Master Doc');
}

console.log(`[Bundle Output] DEBUG: run_id=${runId}, mode=${mode}`);

// Refinement: one known job, supplied by the webhook. No job scan, no watchlist.
if (mode === 'refinement') {
  console.log(`[Bundle Output] mode=refinement, run_id=${runId}, master_doc: ${masterDoc.length} chars, config: ${Object.keys(config).length} keys, database_id: ${databaseId}`);
  return [{
    json: {
      run_id: runId,
      mode: 'refinement',
      config,
      master_doc: masterDoc,
      database_id: databaseId,
      root_folder_id: rootFolderId,
      pricing: $('Transform Pricing').first().json.pricing || {}
    }
  }];
}

// Cover letter generate/refine: one known job from the webhook. No job scan, no watchlist.
if (mode === 'cover_letter') {
  console.log(`[Bundle Output] mode=cover_letter, run_id=${runId}, master_doc: ${masterDoc.length} chars, config: ${Object.keys(config).length} keys, database_id: ${databaseId}`);
  return [{
    json: {
      run_id: runId,
      mode: 'cover_letter',
      config,
      master_doc: masterDoc,
      database_id: databaseId,
      root_folder_id: rootFolderId,
      pricing: $('Transform Pricing').first().json.pricing || {}
    }
  }];
}

if (mode === 'discovery') {
  const existingJobUrls = $('Filter Jobs').first()?.json?.existing_job_urls || [];
  const existingJobRoles = $('Filter Jobs').first()?.json?.existing_job_roles || [];
  const watchlistRows = $('Load Watchlist').all().map(i => i.json);
  const watchlist = watchlistRows
    .filter(row => row && row.company_name)
    .map(row => ({
      company_name: String(row.company_name || '').trim(),
      domain: String(row.domain || '').trim(),
      category: String(row.category || '').trim(),
      priority: Number(row.priority) || null,
      greenhouse_slug: String(row.greenhouse_slug || '').trim(),
      lever_slug: String(row.lever_slug || '').trim(),
      ashby_slug: String(row.ashby_slug || '').trim(),
      workday_url: String(row.workday_url || '').trim(),
      careers_url: String(row.careers_url || '').trim()
    }));
  console.log(`[Bundle Output] mode=discovery, run_id=${runId}, master_doc: ${masterDoc.length} chars, config: ${Object.keys(config).length} keys, existing URLs: ${existingJobUrls.length}, existing roles: ${existingJobRoles.length}, watchlist: ${watchlist.length} companies, database_id: ${databaseId}`);
  return [{
    json: {
      run_id: runId,
      mode: 'discovery',
      config,
      master_doc: masterDoc,
      database_id: databaseId,
      root_folder_id: rootFolderId,
      existing_job_urls: existingJobUrls,
      existing_job_roles: existingJobRoles,
      watchlist,
      pricing: $('Transform Pricing').first().json.pricing || {}
    }
  }];
}

const jobs = $('Filter Jobs').all().map(i => i.json);
console.log(`[Bundle Output] mode=application, run_id=${runId}, master_doc: ${masterDoc.length} chars, config: ${Object.keys(config).length} keys, ready_jobs: ${jobs.length}, database_id: ${databaseId}`);
return [{
  json: {
    run_id: runId,
    mode: 'application',
    ready_jobs: jobs,
    config,
    master_doc: masterDoc,
    database_id: databaseId,
    root_folder_id: rootFolderId,
    pricing: $('Transform Pricing').first().json.pricing || {}
  }
}];

const rows = $input.all().map(i => i.json);
const pricing = {};

rows.forEach(row => {
  if (!row.model) return;
  pricing[row.model] = {
    provider: row.provider || '',
    input_per_million: Number(row.input_per_million) || 0,
    output_per_million: Number(row.output_per_million) || 0,
    cached_input_per_million: Number(row.cached_input_per_million) || 0,
    cache_write_per_million: Number(row.cache_write_per_million) || 0
  };
});

console.log(`[Data Loader] Loaded pricing for ${Object.keys(pricing).length} models`);
return [{ json: { pricing } }];
